 96→      return {
 97→        ...state,
 98→        status: event.status,
 99→        lastEventAt: now,
100→        stallWarning: undefined,
101→        error: event.error,
102→      };
103→
104→    case "agent_file_change":
105→      return {
106→        ...state,
107→        filesChanged: state.filesChanged + 1,
108→        lastEventAt: now,
109→        stallWarning: undefined,
110→        outputEntries: [
111→          ...state.outputEntries,
112→          { kind: "file_change", file: event.file, changeType: event.changeType },
113→        ],
114→      };
115→
116→    case "agent_stall_warning":
117→      return {
118→        ...state,
119→        lastEventAt: now,
120→        stallWarning: {
121→          lastEventAt: event.lastEventAt,
122→          stallDurationSeconds: event.stallDurationSeconds,
123→        },
124→      };
125→
126→    case "agent_token":
127→      return {
128→        ...state,
129→        lastEventAt: now,
130→        stallWarning: undefined,
131→        outputEntries: [
132→          ...state.outputEntries,
133→          { kind: "token", text: event.token },
134→        ],
135→      };
136→
137→    case "agent_prompt":
138→      return {
139→        ...state,
140→        lastEventAt: now,
141→        stallWarning: undefined,
142→        outputEntries: [
143→          { kind: "prompt", text: event.text },
144→        ],
145→      };
146→  }
147→}
148→
149→// ---------------------------------------------------------------------------
150→// Hook return type
151→// ---------------------------------------------------------------------------
152→
153→export type UseAgentSessionReturn = {
154→  state: AgentSessionState;
155→  close: () => void;
156→};
157→
158→// ---------------------------------------------------------------------------
159→// Hook: effect boundary (EventSource lifecycle + stall timer)
160→// ---------------------------------------------------------------------------
161→
162→export function useAgentSession(
163→  streamUrl: string | undefined,
164→  startedAt: string,
165→): UseAgentSessionReturn {
166→  const [state, setState] = useState<AgentSessionState>(() =>
167→    createInitialState(startedAt),
168→  );
169→  const eventSourceRef = useRef<EventSource | undefined>(undefined);
170→  const stallTimerRef = useRef<ReturnType<typeof setTimeout> | undefined>(undefined);
171→
172→  // Timer lifecycle: clearStallTimer is stable (no deps). resetStallTimer depends only on
173→  // clearStallTimer, so it is also stable. Both use stallTimerRef (a ref, not state) to avoid
174→  // stale closures. setState updater form ensures state reads are always current.
175→  const clearStallTimer = useCallback(() => {
176→    if (stallTimerRef.current !== undefined) {
177→      clearTimeout(stallTimerRef.current);
178→      stallTimerRef.current = undefined;
179→    }
180→  }, []);
181→
182→  const resetStallTimer = useCallback(() => {
183→    clearStallTimer();
184→    stallTimerRef.current = setTimeout(() => {
185→      setState((prev) => ({
186→        ...prev,
187→        stallWarning: {
188→          lastEventAt: prev.lastEventAt ?? prev.startedAt,
189→          stallDurationSeconds: STALL_TIMEOUT_MS / 1000,
190→        },
191→      }));
192→    }, STALL_TIMEOUT_MS);
193→  }, [clearStallTimer]);
194→
195→  useEffect(() => {
196→    if (!streamUrl) return;
197→
198→    const eventSource = new EventSource(streamUrl);
199→    eventSourceRef.current = eventSource;
200→
201→    function handleEvent(eventType: string, rawData: string) {
202→      // Reset stall timer on every received event, even if parsing fails.
203→      // A received event proves the connection is alive.
204→      resetStallTimer();
205→
206→      try {
207→        const data = JSON.parse(rawData);
208→        const event: AgentEvent = { ...data, type: eventType };
209→        setState((prev) => reduceAgentSessionEvent(prev, event));
210→
211→        // Close on terminal status
212→        if (eventType === "agent_status" && isTerminalStatus(data.status)) {
213→          eventSource.close();
214→          clearStallTimer();
215→        }
216→      } catch {
217→        // Malformed event data -- state not updated but stall timer is reset
218→        console.warn(`Failed to parse ${eventType} event data`);
219→      }
220→    }
221→
222→    eventSource.addEventListener("agent_status", (e) =>
223→      handleEvent("agent_status", e.data),
224→    );
225→    eventSource.addEventListener("agent_file_change", (e) =>
226→      handleEvent("agent_file_change", e.data),
227→    );
228→    eventSource.addEventListener("agent_stall_warning", (e) =>
229→      handleEvent("agent_stall_warning", e.data),
230→    );
231→    eventSource.addEventListener("agent_token", (e) =>
232→      handleEvent("agent_token", e.data),
233→    );
234→    eventSource.addEventListener("agent_prompt", (e) =>
235→      handleEvent("agent_prompt", e.data),
236→    );
237→
238→    eventSource.onerror = () => {
239→      eventSource.close();
240→      clearStallTimer();
241→      setState((prev) => ({
242→        ...prev,
243→        status: "error",
244→        connectionError: "Connection lost",
245→      }));
246→    };
247→
248→    // Start stall timer
249→    resetStallTimer();
250→
251→    return () => {
252→      eventSource.close();
253→      eventSourceRef.current = undefined;
254→      clearStallTimer();
255→    };
256→  }, [streamUrl, resetStallTimer, clearStallTimer]);
257→
258→  const close = useCallback(() => {
259→    if (eventSourceRef.current) {
260→      eventSourceRef.current.close();
261→      eventSourceRef.current = undefined;
262→    }
263→    clearStallTimer();
264→  }, [clearStallTimer]);
265→
266→  return { state, close };
267→}
