 25→  config: OpencodeConfig,
 26→  worktreePath: string,
 27→  taskId: string,
 28→) => Promise<OpenCodeHandle>;
 29→
 30→export type SessionDeps = {
 31→  surreal: Surreal;
 32→  shellExec: ShellExec;
 33→  brainBaseUrl: string;
 34→  spawnOpenCode?: SpawnOpenCodeFn;
 35→};
 36→
 37→export type SessionErrorCode =
 38→  | "TASK_NOT_FOUND"
 39→  | "TASK_NOT_ASSIGNABLE"
 40→  | "AGENT_ALREADY_ACTIVE"
 41→  | "WORKSPACE_MISMATCH"
 42→  | "MISSING_TASK_ID"
 43→  | "WORKTREE_ERROR"
 44→  | "SESSION_NOT_FOUND"
 45→  | "SESSION_ERROR";
 46→
 47→export type SessionError = {
 48→  code: SessionErrorCode;
 49→  message: string;
 50→  httpStatus: number;
 51→};
 52→
 53→export type SessionResult<T> =
 54→  | { ok: true; value: T }
 55→  | { ok: false; error: SessionError };
 56→
 57→export type OrchestratorSessionResult = SessionResult<{
 58→  agentSessionId: string;
 59→  streamId: string;
 60→  worktreeBranch: string;
 61→}>;
 62→
 63→export type SessionStatusResult = SessionResult<{
 64→  orchestratorStatus: OrchestratorStatus;
 65→  worktreeBranch?: string;
 66→  worktreePath?: string;
 67→  lastEventAt?: string;
 68→  startedAt?: string;
 69→  error?: string;
 70→}>;
 71→
 72→export type AbortSessionResult = SessionResult<{
 73→  aborted: boolean;
 74→  sessionId: string;
 75→}>;
 76→
 77→export type AcceptSessionResult = SessionResult<{
 78→  accepted: boolean;
 79→  sessionId: string;
 80→}>;
 81→
 82→export type ReviewResult = SessionResult<{
 83→  taskTitle: string;
 84→  diff: import("./worktree-manager").DiffResult;
 85→  session: {
 86→    orchestratorStatus: string;
 87→    worktreeBranch?: string;
 88→    startedAt?: string;
 89→    lastEventAt?: string;
 90→    toolCallCount?: number;
 91→    filesEdited?: number;
 92→  };
 93→}>;
 94→
 95→export type RejectSessionResult = SessionResult<{
 96→  rejected: boolean;
 97→  continuing: boolean;
 98→}>;
 99→
100→export type PromptSessionResult = SessionResult<{
101→  delivered: boolean;
102→}>;
103→
104→// ---------------------------------------------------------------------------
105→// In-memory handle registry — maps agentSessionId to OpenCodeHandle
106→// ---------------------------------------------------------------------------
107→
108→const handleRegistry = new Map<string, OpenCodeHandle>();
109→
110→// Exported for testing cleanup
111→export function clearHandleRegistry(): void {
112→  handleRegistry.clear();
113→}
114→
115→// ---------------------------------------------------------------------------
116→// Event iteration — port (dependencies as function signatures)
117→// ---------------------------------------------------------------------------
118→
119→export type EventIterationDeps = {
120→  emitEvent: (streamId: string, event: StreamEvent) => void;
121→  updateSessionStatus: (
122→    sessionId: string,
123→    status: OrchestratorStatus,
124→    error?: string,
125→  ) => Promise<void>;
126→  updateLastEventAt: (sessionId: string) => Promise<void>;
127→  getSessionStatus: (sessionId: string) => Promise<OrchestratorStatus>;
128→  startStallDetector: (sessionId: string, streamId: string) => StallDetectorHandle;
129→};
130→
131→const TERMINAL_STATUSES: ReadonlySet<string> = new Set<string>(
132→  TERMINAL_ORCHESTRATOR_STATUSES,
133→);
134→
135→/**
136→ * Iterates the OpenCode event stream, forwarding events through the event
137→ * bridge. Transitions session to "active" on first event, starts stall
138→ * detection, and stops on terminal status or error.
139→ *
140→ * Returns a Promise that resolves when iteration ends (for testing).
141→ * In production, this is launched fire-and-forget.
142→ */
143→export function startEventIteration(
144→  deps: EventIterationDeps,
145→  eventStream: AsyncIterable<unknown>,
146→  streamId: string,
147→  sessionId: string,
148→): Promise<void> {
149→  const stallDetector = deps.startStallDetector(sessionId, streamId);
150→
151→  const bridge = startEventBridge(
152→    {
153→      emitEvent: deps.emitEvent,
154→      updateLastEventAt: deps.updateLastEventAt,
155→    },
156→    streamId,
157→    sessionId,
158→    stallDetector,
159→  );
160→
161→  let firstEventReceived = false;
162→
163→  async function iterate(): Promise<void> {
164→    try {
165→      for await (const rawEvent of eventStream) {
166→        // Check if session has reached terminal status
167→        const currentStatus = await deps.getSessionStatus(sessionId);
168→        if (TERMINAL_STATUSES.has(currentStatus)) {
169→          break;
170→        }
171→
172→        // Transition to active on first event
173→        if (!firstEventReceived) {
174→          firstEventReceived = true;
175→          await deps.updateSessionStatus(sessionId, "active");
176→        }
177→
178→        // Forward through event bridge (transform + emit + stall detection)
179→        bridge.handleEvent(rawEvent as OpencodeEvent);
180→      }
181→    } catch (err) {
182→      const errorMessage = err instanceof Error ? err.message : String(err);
183→      await deps.updateSessionStatus(sessionId, "error", errorMessage);
184→    } finally {
185→      bridge.stop();
186→    }
187→  }
188→
189→  return iterate();
190→}
191→
192→// ---------------------------------------------------------------------------
193→// Pure helpers
194→// ---------------------------------------------------------------------------
195→
196→function pickDefined<T extends Record<string, unknown>>(obj: T): Partial<T> {
197→  const result: Record<string, unknown> = {};
198→  for (const [key, value] of Object.entries(obj)) {
199→    if (value !== undefined && value !== null) {
200→      result[key] = value;
201→    }
202→  }
203→  return result as Partial<T>;
204→}
205→
206→function sessionNotFound(sessionId: string): SessionError {
207→  return {
208→    code: "SESSION_NOT_FOUND",
209→    message: `Session not found: ${sessionId}`,
210→    httpStatus: 404,
211→  };
212→}
213→
214→function worktreeError(message: string): SessionError {
215→  return {
216→    code: "WORKTREE_ERROR",
217→    message,
218→    httpStatus: 500,
219→  };
220→}
221→
222→function fromAssignmentError(error: AssignmentError): SessionError {
223→  return {
224→    code: error.code as SessionErrorCode,
225→    message: error.message,
226→    httpStatus: error.httpStatus,
227→  };
228→}
229→
230→// ---------------------------------------------------------------------------
231→// Session row shape (DB query result)
232→// ---------------------------------------------------------------------------
233→
234→type SessionRow = {
235→  id: RecordId<"agent_session", string>;
236→  orchestrator_status?: string;
237→  worktree_branch?: string;
238→  worktree_path?: string;
239→  started_at?: string;
240→  last_event_at?: string;
241→  task_id?: RecordId<"task", string>;
242→  workspace?: RecordId<"workspace", string>;
243→  error?: string;
244→};
245→
246→type SessionLookup =
247→  | { ok: true; session: SessionRow; record: RecordId<"agent_session", string>; status: OrchestratorStatus }
248→  | { ok: false; error: SessionError };
249→
250→async function lookupSession(
251→  surreal: Surreal,
252→  sessionId: string,
253→): Promise<SessionLookup> {
254→  const record = new RecordId("agent_session", sessionId);
255→  const session = await surreal.select<SessionRow>(record);
256→  if (!session) {
257→    return { ok: false, error: sessionNotFound(sessionId) };
258→  }
259→  if (!session.orchestrator_status) {
260→    throw new Error(`agent_session ${sessionId} missing orchestrator_status — data corruption`);
261→  }
262→  const status = session.orchestrator_status as OrchestratorStatus;
263→  return { ok: true, session, record, status };
264→}
265→
266→function requireWorkspace(session: SessionRow, sessionId: string): RecordId<"workspace", string> {
267→  if (!session.workspace) {
268→    throw new Error(`agent_session ${sessionId} missing workspace — data corruption`);
269→  }
270→  return session.workspace as RecordId<"workspace", string>;
271→}
272→
273→function generateStreamId(sessionId: string): string {
274→  return `stream-${sessionId}`;
275→}
276→
277→function slugFromTitle(title: string): string {
278→  return title
279→    .toLowerCase()
280→    .replace(/[^a-z0-9]+/g, "-")
281→    .replace(/^-|-$/g, "")
282→    .slice(0, 50);
283→}
284→
285→// ---------------------------------------------------------------------------
286→// createOrchestratorSession
287→// ---------------------------------------------------------------------------
288→
289→type CreateSessionInput = {
290→  surreal: Surreal;
291→  shellExec: ShellExec;
292→  brainBaseUrl: string;
293→  workspaceId: string;
294→  taskId: string;
295→  authToken: string;
296→  spawnOpenCode?: SpawnOpenCodeFn;
297→  validateAssignment: (
298→    surreal: Surreal,
299→    workspaceId: string,
300→    taskId: string,
301→  ) => Promise<AssignmentResult>;
302→  createAgentSession: (input: {
303→    surreal: Surreal;
304→    agent: string;
305→    workspaceRecord: RecordId<"workspace", string>;
306→    taskId?: string;
307→  }) => Promise<{ session_id: string }>;
308→};
309→
310→export async function createOrchestratorSession(
311→  input: CreateSessionInput,
312→): Promise<OrchestratorSessionResult> {
313→  // 1. Validate assignment eligibility
314→  const assignmentResult = await input.validateAssignment(
315→    input.surreal,
316→    input.workspaceId,
317→    input.taskId,
318→  );
319→
320→  if (!assignmentResult.ok) {
321→    return { ok: false, error: fromAssignmentError(assignmentResult.error) };
322→  }
323→
324→  const { validation } = assignmentResult;
325→  const taskSlug = slugFromTitle(validation.title);
326→  const repoRoot = validation.repoPath;
327→
328→  // 2. Create worktree
329→  const worktreeResult = await createWorktree(
330→    input.shellExec,
331→    repoRoot,
332→    taskSlug,
333→  );
334→
335→  if (!worktreeResult.ok) {
336→    return {
337→      ok: false,
338→      error: worktreeError(worktreeResult.error.message),
339→    };
340→  }
341→
342→  const { branchName, worktreePath } = worktreeResult.value;
343→
344→  // 3. Create agent_session record
345→  const { session_id: agentSessionId } = await input.createAgentSession({
346→    surreal: input.surreal,
347→    agent: "opencode",
348→    workspaceRecord: validation.workspaceRecord,
349→    taskId: input.taskId,
350→  });
351→
352→  const streamId = generateStreamId(agentSessionId);
353→
354→  // 4. Build config and spawn OpenCode
355→  const config = buildOpencodeConfig({
356→    brainBaseUrl: input.brainBaseUrl,
357→    workspaceId: input.workspaceId,
358→    authToken: input.authToken,
359→  });
360→
361→  const spawnFn = input.spawnOpenCode ?? defaultSpawnOpenCode;
362→  let handle: OpenCodeHandle;
363→  try {
364→    handle = await spawnFn(config, worktreePath, input.taskId);
365→  } catch (err) {
366→    // Rollback: remove worktree and delete agent_session on spawn failure
367→    await removeWorktree(input.shellExec, repoRoot, branchName);
368→    const sessionRecord = new RecordId("agent_session", agentSessionId);
369→    await input.surreal.delete(sessionRecord);
370→    return {
371→      ok: false,
372→      error: worktreeError(`Failed to spawn OpenCode: ${err instanceof Error ? err.message : String(err)}`),
373→    };
374→  }
375→
376→  // 5. Register handle for later abort
377→  handleRegistry.set(agentSessionId, handle);
378→
379→  // 6. Update agent_session with orchestrator fields
380→  const sessionRecord = new RecordId("agent_session", agentSessionId);
381→  await input.surreal.update(sessionRecord).merge({
382→    orchestrator_status: "spawning" as OrchestratorStatus,
383→    worktree_branch: branchName,
384→    worktree_path: worktreePath,
385→    opencode_session_id: handle.sessionId,
386→    stream_id: streamId,
387→  });
388→
389→  return {
390→    ok: true,
391→    value: {
392→      agentSessionId,
393→      streamId,
394→      worktreeBranch: branchName,
395→    },
396→  };
397→}
398→
399→// Default spawn -- placeholder for production use
400→async function defaultSpawnOpenCode(
401→  _config: OpencodeConfig,
402→  _worktreePath: string,
403→  _taskId: string,
404→): Promise<OpenCodeHandle> {
405→  throw new Error(
406→    "spawnOpenCode not provided -- must be injected for production use",
407→  );
408→}
409→
410→// ---------------------------------------------------------------------------
411→// getOrchestratorSessionStatus
412→// ---------------------------------------------------------------------------
413→
414→type GetStatusInput = {
415→  surreal: Surreal;
416→  sessionId: string;
417→};
418→
419→export async function getOrchestratorSessionStatus(
420→  input: GetStatusInput,
421→): Promise<SessionStatusResult> {
422→  const lookup = await lookupSession(input.surreal, input.sessionId);
423→  if (!lookup.ok) {
424→    return { ok: false, error: lookup.error };
425→  }
426→  const { session } = lookup;
427→
428→  return {
429→    ok: true,
430→    value: {
431→      orchestratorStatus: lookup.status,
432→      ...pickDefined({
433→        worktreeBranch: session.worktree_branch,
434→        worktreePath: session.worktree_path,
435→        startedAt: session.started_at,
436→        lastEventAt: session.last_event_at,
437→        error: session.error,
438→      }),
439→    },
440→  };
441→}
442→
443→// ---------------------------------------------------------------------------
444→// abortOrchestratorSession
445→// ---------------------------------------------------------------------------
446→
447→type AbortSessionInput = {
448→  surreal: Surreal;
449→  shellExec: ShellExec;
450→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
451→  sessionId: string;
452→  endAgentSession: (input: {
453→    surreal: Surreal;
454→    workspaceRecord: RecordId<"workspace", string>;
455→    sessionId: string;
456→    summary: string;
457→  }) => Promise<{ session_id: string; ended: boolean }>;
458→};
459→
460→export async function abortOrchestratorSession(
461→  input: AbortSessionInput,
462→): Promise<AbortSessionResult> {
463→  const lookup = await lookupSession(input.surreal, input.sessionId);
464→  if (!lookup.ok) {
465→    return { ok: false, error: lookup.error };
466→  }
467→  const { session, record: sessionRecord } = lookup;
468→
469→  // 1. Kill the OpenCode process if handle exists
470→  const handle = handleRegistry.get(input.sessionId);
471→  if (handle) {
472→    handle.abort();
473→    handleRegistry.delete(input.sessionId);
474→  }
475→
476→  // 2. Update orchestrator_status to aborted
477→  await input.surreal.update(sessionRecord).merge({
478→    orchestrator_status: "aborted" as OrchestratorStatus,
479→  });
480→
481→  const workspaceRecord = requireWorkspace(session, input.sessionId);
482→
483→  // 3. Remove worktree if branch name exists
484→  if (session.worktree_branch) {
485→    const repoRoot = await input.resolveRepoRoot(workspaceRecord);
486→    await removeWorktree(input.shellExec, repoRoot, session.worktree_branch);
487→  }
488→
489→  // 4. Return task to ready
490→  if (session.task_id) {
491→    await input.surreal.update(session.task_id).merge({
492→      status: "ready",
493→      updated_at: new Date(),
494→    });
495→  }
496→
497→  // 5. End the agent session
498→  await input.endAgentSession({
499→    surreal: input.surreal,
500→    workspaceRecord,
501→    sessionId: input.sessionId,
502→    summary: "Session aborted",
503→  });
504→
505→  return {
506→    ok: true,
507→    value: {
508→      aborted: true,
509→      sessionId: input.sessionId,
510→    },
511→  };
512→}
513→
514→// ---------------------------------------------------------------------------
515→// acceptOrchestratorSession
516→// ---------------------------------------------------------------------------
517→
518→type AcceptSessionInput = {
519→  surreal: Surreal;
520→  sessionId: string;
521→  summary: string;
522→  endAgentSession: (input: {
523→    surreal: Surreal;
524→    workspaceRecord: RecordId<"workspace", string>;
525→    sessionId: string;
526→    summary: string;
527→  }) => Promise<{ session_id: string; ended: boolean }>;
528→};
529→
530→export async function acceptOrchestratorSession(
531→  input: AcceptSessionInput,
532→): Promise<AcceptSessionResult> {
533→  const lookup = await lookupSession(input.surreal, input.sessionId);
534→  if (!lookup.ok) {
535→    return { ok: false, error: lookup.error };
536→  }
