      if (result.ok && wiringDeps.sseRegistry) {
        const { agentSessionId, streamId } = result.value;
        wiringDeps.sseRegistry.registerMessage(streamId);

        const handle = lifecycle.getHandle(agentSessionId);
        if (handle) {
